const configNode = $("Config").first().json;
const webhookData = configNode.webhookData;

let finalEmail = null;
let finalName = null;

// 1. Recoger la decisión de la IA y LIMPIAR el Markdown
try {
  let aiRawText = $("Basic LLM Chain").first().json.text;

  // Limpiamos las etiquetas ```json y ``` que añade la IA
  const cleanJsonText = aiRawText.replace(/```json/g, "").replace(/```/g, "").trim();

  const aiResult = JSON.parse(cleanJsonText);

  if (aiResult.match_encontrado || aiResult.match_exitoso) {
    finalEmail = aiResult.email || aiResult.email_cliente;
    finalName = aiResult.nombre_ghl || aiResult.nombre_exacto || aiResult.nombre_cliente;
  }
} catch (e) {
  console.log("Error parseando el JSON de la IA, intentando fallback de Fathom...");
}

// 2. FALLBACK: Si la IA falló o no dio formato correcto, usamos Fathom
if (!finalEmail) {
  const fGuest = (webhookData.calendar_invitees || []).find(i => i.is_external === true);
  finalEmail = fGuest?.email;
  finalName = fGuest?.name;
}

// Detener si después de todo no hay email (evita errores en nodos siguientes)
if (!finalEmail) return [];

// 3. Formatear el resumen para GHL
const cleanSummary = (webhookData.default_summary?.markdown_formatted || "")
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1') // Quita links de Fathom
  .replace(/\n/g, '<br>');

const noteBody = `<b>Reunión ${new Date(webhookData.scheduled_start_time).toLocaleDateString('en-GB')}</b><br><br><b>Resumen:</b><br>${cleanSummary}<br><br><b>Grabación:</b> ${webhookData.share_url}`;

// 4. SALIDA FINAL
return [{
  json: {
    attendee_email: finalEmail.toLowerCase().trim(),
    attendee_name: finalName || 'Cliente',
    note_body: noteBody,
    action_items: webhookData.action_items || [],
    meeting_date: webhookData.scheduled_start_time,
    location_id: configNode.ghl_location_id
  }
}];

// Extract conversationId from search results (existing conversation)
const conversations = $('Search Conversation').item.json.conversations;
if (conversations && conversations.length > 0) {
  return [{ json: { conversationId: conversations[0].id } }];
}
throw new Error('No conversation found');

// Extract conversationId from newly created conversation
const item = $input.first().json;
const conversationId = item.conversation?.id || item.id;
if (!conversationId) {
  throw new Error('Could not get conversationId from create response');
}
return [{ json: { conversationId } }];

const contactId = $('Search GHL Contact').item.json.contacts[0].id;
const actionItems = $('Parse External Attendees').item.json.action_items || [];
const meetingTitle = $('Parse External Attendees').item.json.meeting_title;

// Calculate due date (7 days from now at 17:00)
const dueDate = new Date();
dueDate.setDate(dueDate.getDate() + 7);
dueDate.setHours(17, 0, 0, 0);

return actionItems.map(item => ({
  json: {
    contactId: contactId,
    title: item.description,
    completed: item.completed || false,
    dueDate: dueDate.toISOString(),
    body: `<b>From meeting:</b> ${meetingTitle}`
  }
}));

// Definimos los 3 IDs de calendarios secundarios que me pasaste
const calendarIds = [
  "c_45cff20d890ab290c2643272e5ed5fda501e6089c3e76c443357c4759f219391@group.calendar.google.com", // Marc
  "c_29e30c239c9e55755821951d6df8b558b75e276932aa06c776243fb839b34683@group.calendar.google.com", // Pepe
  "c_27717e11b6764cad9361c3a37e0e8e5d61aaa689e9d7d0a6c273666f14caa13c@group.calendar.google.com"  // Rafael
];

// Creamos 3 items de salida para que el siguiente nodo se ejecute 3 veces
return calendarIds.map(id => {
  return {
    json: {
      calendarId: id
    }
  };
});

// Aplana todos los eventos de los 3 calendarios en una sola lista
const allEvents = $input.all().flatMap(item => 
  Array.isArray(item.json) ? item.json : [item.json]
);

return [{
  json: {
    lista_eventos: allEvents
  }
}];

